sql.where:

    (r.title LIKE CONCAT('%', #{f.keyword}, '%') OR r.description LIKE CONCAT('%', #{f.keyword}, '%') OR r.file_name LIKE CONCAT('%', #{f.keyword}, '%'))

AND r.category_id = #{f.categoryId}
AND r.applicable_grade = #{f.applicableGrade}
AND r.semester = #{f.semester}
AND r.resource_format = #{f.resourceFormat}

    AND EXISTS (
        SELECT 1 FROM resource_tags rt2 INNER JOIN tags t2 ON t2.id = rt2.tag_id
        WHERE rt2.resource_id = r.id AND t2.name = #{f.tagName}
    )

AND (r.status = 'public' OR r.user_id = #{currentUserId})

mapper.select:
SELECT 
FROM resources r
         LEFT JOIN users u ON u.id = r.user_id
         LEFT JOIN kg_category c ON c.id = r.category_id
         LEFT JOIN kg_category c2 ON c2.id = c.parent_id
         LEFT JOIN kg_category c3 ON c3.id = c2.parent_id
         LEFT JOIN kg_favorites fav2 ON fav2.resource_id = r.id AND fav2.user_id = #{currentUserId}
WHERE r.status = 'public' OR r.user_id = #{currentUserId}
ORDER BY r.created_at DESC LIMIT #{limit}

SELECT 
FROM kg_favorites fav
         INNER JOIN resources r ON r.id = fav.resource_id
         LEFT JOIN users u ON u.id = r.user_id
         LEFT JOIN kg_category c ON c.id = r.category_id
         LEFT JOIN kg_category c2 ON c2.id = c.parent_id
         LEFT JOIN kg_category c3 ON c3.id = c2.parent_id
         LEFT JOIN kg_favorites fav2 ON fav2.resource_id = r.id AND fav2.user_id = #{userId}
WHERE fav.user_id = #{userId}
ORDER BY fav.created_at DESC LIMIT #{offset}, #{limit}
